import { Controller } from '@nestjs/common';
import { CommandBus, QueryBus } from '@nestjs/cqrs';
import { ProjectRepository } from '@ultimatebackend/repository';
import {
  CreateProjectRequest,
  CreateProjectResponse,
  DeleteProjectRequest,
  DeleteProjectResponse,
  FindProjectsRequest,
  FindProjectsResponse,
  ReadProjectRequest,
  ReadProjectResponse,
  ProjectService,
  UpdateProjectRequest,
  UpdateProjectResponse,
} from '@ultimatebackend/proto-schema/project';
import { GrpcMethod } from '@nestjs/microservices';
import {
  CreateProjectCommand,
  DeleteProjectCommand,
  UpdateProjectCommand,
  GetProjectQuery,
  GetProjectsQuery,
} from './cqrs';
import { getIdentityFromCtx } from '@ultimatebackend/core';

@Controller('projects')
export class ProjectsController implements ProjectService<any> {
  constructor(
    private readonly commandBus: CommandBus,
    private readonly queryBus: QueryBus,
    private readonly spaceRepository: ProjectRepository,
  ) {}

  @GrpcMethod('ProjectService')
  createProject(
    request: CreateProjectRequest,
    ctx: any,
  ): Promise<CreateProjectResponse> {
    const { user } = getIdentityFromCtx(ctx);
    return this.commandBus.execute(
      new CreateProjectCommand(request, user, this.spaceRepository),
    );
  }

  @GrpcMethod('ProjectService')
  deleteProject(
    request: DeleteProjectRequest,
    ctx: any,
  ): Promise<DeleteProjectResponse> {
    const { user } = getIdentityFromCtx(ctx);
    return this.commandBus.execute(
      new DeleteProjectCommand(request, user, this.spaceRepository),
    );
  }

  @GrpcMethod('ProjectService')
  findProjects(
    request: FindProjectsRequest,
    ctx: any,
  ): Promise<FindProjectsResponse> {
    return this.queryBus.execute(
      new GetProjectsQuery(this.spaceRepository, request),
    );
  }

  @GrpcMethod('ProjectService')
  readProject(
    request: ReadProjectRequest,
    ctx: any,
  ): Promise<ReadProjectResponse> {
    return this.queryBus.execute(
      new GetProjectQuery(request, this.spaceRepository),
    );
  }

  @GrpcMethod('ProjectService')
  updateProject(
    request: UpdateProjectRequest,
    ctx: any,
  ): Promise<UpdateProjectResponse> {
    const { user } = getIdentityFromCtx(ctx);
    return this.commandBus.execute(
      new UpdateProjectCommand(request, user, this.spaceRepository),
    );
  }
}

import { Controller, Logger } from '@nestjs/common';
import { CommandBus, QueryBus } from '@nestjs/cqrs';
import {
  CreateWebhookRequest,
  CreateWebhookResponse,
  DeleteWebhookRequest,
  DeleteWebhookResponse,
  FindWebhookRequest,
  FindWebhookResponse,
  ReadWebhookRequest,
  ReadWebhookResponse,
  UpdateWebhookRequest,
  UpdateWebhookResponse,
  WebhookService,
} from '@ultimatebackend/proto-schema/webhook';
import { WebhookRepository } from '@ultimatebackend/repository';
import { getIdentityFromCtx } from '@ultimatebackend/core';
import {
  CreateWebhookCommand,
  DeleteWebhookCommand,
  UpdateWebhookCommand,
  FindWebhookQuery,
  ReadWebhookQuery,
} from '../cqrs';
import { GrpcMethod } from '@nestjs/microservices';

@Controller('webhook')
export class WebhookController implements WebhookService<any> {
  logger = new Logger(this.constructor.name);

  constructor(
    private readonly repo: WebhookRepository,
    private readonly queryBus: QueryBus,
    private readonly commandBus: CommandBus,
  ) {}

  @GrpcMethod('WebhookService')
  createWebhook(
    request: CreateWebhookRequest,
    ctx: any,
  ): Promise<CreateWebhookResponse> {
    const { user } = getIdentityFromCtx(ctx);
    return this.commandBus.execute(
      new CreateWebhookCommand(request, this.repo, user),
    );
  }

  @GrpcMethod('WebhookService')
  deleteWebhook(
    request: DeleteWebhookRequest,
    ctx: any,
  ): Promise<DeleteWebhookResponse> {
    return this.commandBus.execute(
      new DeleteWebhookCommand(request, this.repo),
    );
  }

  @GrpcMethod('WebhookService')
  findWebhook(
    request: FindWebhookRequest,
    ctx: any,
  ): Promise<FindWebhookResponse> {
    return this.queryBus.execute(new FindWebhookQuery(request, this.repo));
  }

  @GrpcMethod('WebhookService')
  readWebhook(
    request: ReadWebhookRequest,
    ctx: any,
  ): Promise<ReadWebhookResponse> {
    return this.queryBus.execute(new ReadWebhookQuery(request, this.repo));
  }

  @GrpcMethod('WebhookService')
  updateWebhook(
    request: UpdateWebhookRequest,
    ctx: any,
  ): Promise<UpdateWebhookResponse> {
    return this.commandBus.execute(
      new UpdateWebhookCommand(request, this.repo),
    );
  }
}

import { ApiProperty } from '@nestjs/swagger';

export type OperationLogEssentialProperties = Readonly<
  Required<{
    userId: string;
    username: string;
    domain: string;
    moduleName: string;
    description: string;
    requestId: string;
    method: string;
    url: string;
    ip: string;
    userAgent: string | null;
    params: any;
    body: any;
    response: any;
    startTime: Date;
    endTime: Date;
    duration: number;
  }>
>;

export type OperationLogProperties = OperationLogEssentialProperties;

export class OperationLogReadModel {
  @ApiProperty({ description: 'The unique identifier of the operation log' })
  id: string;

  @ApiProperty({ description: 'User ID associated with the operation' })
  userId: string;

  @ApiProperty({ description: 'Username associated with the operation' })
  username: string;

  @ApiProperty({ description: 'Domain where the operation occurred' })
  domain: string;

  @ApiProperty({ description: 'Module where the operation occurred' })
  moduleName: string;

  @ApiProperty({ description: 'Description of the operation' })
  description: string;

  @ApiProperty({ description: 'Request ID associated with the operation' })
  requestId: string;

  @ApiProperty({ description: 'HTTP method used in the operation' })
  method: string;

  @ApiProperty({ description: 'URL accessed during the operation' })
  url: string;

  @ApiProperty({
    description: 'IP address from which the operation was initiated',
  })
  ip: string;

  @ApiProperty({
    description: 'User agent of the device used in the operation',
    nullable: true,
  })
  userAgent: string | null;

  @ApiProperty({
    description: 'Parameters used in the operation',
  })
  params: any;

  @ApiProperty({
    description: 'Body of the request used in the operation',
  })
  body: any;

  @ApiProperty({
    description: 'Response returned from the operation',
  })
  response: any;

  @ApiProperty({
    description: 'Start time of the operation',
    type: 'string',
    format: 'date-time',
  })
  startTime: Date;

  @ApiProperty({
    description: 'End time of the operation',
    type: 'string',
    format: 'date-time',
  })
  endTime: Date;

  @ApiProperty({ description: 'Duration of the operation in milliseconds' })
  duration: number;
}

import { ApiProperty } from '@nestjs/swagger';

export type TokensEssentialProperties = Readonly<
  Required<{
    accessToken: string;
    refreshToken: string;
    status: string;
    userId: string;
    username: string;
    domain: string;
    ip: string;
    address: string;
    userAgent: string;
    requestId: string;
    type: string;
    createdBy: string;
  }>
>;

export type TokensOptionalProperties = Readonly<
  Partial<{
    port: number | null;
  }>
>;

export type TokensProperties = TokensEssentialProperties &
  TokensOptionalProperties;

export class TokensReadModel {
  accessToken: string;

  refreshToken: string;

  status: string;

  userId: string;

  @ApiProperty({ description: 'Username associated with the login event' })
  username: string;

  @ApiProperty({ description: 'Domain where the login occurred' })
  domain: string;

  @ApiProperty({
    description: 'Time when the login occurred',
    type: 'string',
    format: 'date-time',
  })
  loginTime: Date;

  @ApiProperty({ description: 'IP address from which the login was attempted' })
  ip: string;

  @ApiProperty({
    description: 'Port number used for the login attempt',
    nullable: true,
  })
  port: number | null;

  @ApiProperty({
    description: 'Physical or virtual address where the login occurred',
  })
  address: string;

  @ApiProperty({ description: 'User agent of the device used for logging in' })
  userAgent: string;

  @ApiProperty({ description: 'Request ID associated with the login event' })
  requestId: string;

  @ApiProperty({ description: 'Type of login event (e.g., success, failure)' })
  type: string;

  @ApiProperty({
    description: 'Date and time when the log was created',
    type: 'string',
    format: 'date-time',
  })
  createdAt: Date;

  createdBy: string;
}
